// E2e tests for category: keywords
package e2e_test

import (
	"encoding/json"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"

	kreuzberg "github.com/kreuzberg-dev/kreuzberg/v4"
)

func Test_KeywordsRake(t *testing.T) {
	// Tests keyword extraction using RAKE algorithm
	var config kreuzberg.ExtractionConfig
	if err := json.Unmarshal([]byte(`{"keywords":{"algorithm":"rake","max_keywords":10}}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := kreuzberg.ExtractFileSync(`pdf/fake_memo.pdf`, nil, config)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if strings.TrimSpace(result.MimeType) != `application/pdf` {
		t.Errorf("equals mismatch: got %v", result.MimeType)
	}
	assert.GreaterOrEqual(t, len(result.Content), 10, "expected length >= 10")
	if len(result.Keywords) == 0 {
		t.Errorf("expected non-empty value")
	}
	assert.GreaterOrEqual(t, len(result.Keywords), 1, "expected at least 1 elements")
	if result.KeywordsCount > 10 {
		t.Errorf("expected <= 10, got %v", result.KeywordsCount)
	}
}

